
import asyncio
import contextvars
import logging
from typing import Any, AsyncGenerator, Dict, Optional, Set
import time
from dataclasses import dataclass

from agent_framework import Workflow
from starlette.middleware.base import BaseHTTPMiddleware

# Context variable to pass response_id from the HTTP request layer to the Workflow.run patch.
#
# The AgentServer SDK strips metadata when calling Workflow.run() — it only passes
# the converted message, not the original request metadata. So the run patch cannot
# extract response_id from its arguments when called via the SDK's standard /responses path.
#
# To bridge this gap, we use a Starlette middleware that reads `x-agentdev-response-id` header
# from the incoming request and sets it on this context variable. The patched run reads
# it from here. contextvars is scoped per async task, so concurrent requests don't interfere.
_current_response_id: contextvars.ContextVar[Optional[str]] = contextvars.ContextVar(
    '_current_response_id', default=None
)

@dataclass
class AgentFrameworkEvent:
    """
    Wrapper for an Agent Framework event captured during execution.
    """
    timestamp: float
    raw_event: Any

class DiagnosticStore:
    """
    Thread-safe store for diagnostic events, keyed by response_id.
    
    This store holds events generated during workflow execution that are not part of the standard
    response stream (e.g., intermediate steps, debug info). Clients can stream these events
    separately using the diagnostics endpoint.
    """
    
    def __init__(self, ttl_seconds: int = 1800, max_capacity: int = 1024, max_stream_capacity: int = 128):
        """
        Initialize the diagnostic store.
        
        Args:
            ttl_seconds: Time-to-live for unconsumed diagnostic streams (default 30 mins).
            max_capacity: Maximum number of concurrent unconsumed items to buffer.
            max_stream_capacity: Maximum number of queues that stream() may auto-create for
                                 unknown response_ids. Prevents unbounded growth from
                                 unauthenticated or misbehaving clients.
        """
        self._events: Dict[str, asyncio.Queue] = {}
        self._created_at: Dict[str, float] = {}
        self._completed: Set[str] = set()
        self._ttl_seconds = ttl_seconds
        self._max_capacity = max_capacity
        self._max_stream_capacity = max_stream_capacity
    
    def push(self, response_id: str, event: AgentFrameworkEvent):
        """
        Push an event to the store for a given response_id.
        
        Args:
            response_id: The unique identifier for the response stream.
            event: The event data object to store.
        """
        if response_id in self._completed:
            logging.debug(f"Event for completed response {response_id}: {type(event.raw_event).__name__}")
            return
            
        # Create queue if not exists
        if response_id not in self._events:
            self._cleanup()
            self._events[response_id] = asyncio.Queue()
            self._created_at[response_id] = time.time()
            
        self._events[response_id].put_nowait(event)
    
    def complete(self, response_id: str):
        """
        Mark a response stream as complete.
        
        This signals to any consumers that no more events will be produced for this response_id.
        
        Args:
            response_id: The unique identifier for the response stream.
        """
        self._completed.add(response_id)
        if response_id in self._events:
            self._events[response_id].put_nowait(None)  # sentinel
            
    def _cleanup(self):
        """Remove expired or excess streams."""
        now = time.time()
        expired_ids = [
            rid for rid, created in self._created_at.items() 
            if now - created > self._ttl_seconds
        ]
        
        # Also enforce capacity limit (simple FIFO)
        if len(self._events) >= self._max_capacity and not expired_ids:
            # If no expired items but at capacity, drop the oldest one
            if self._created_at:
                oldest_id = min(self._created_at, key=self._created_at.get)
                expired_ids.append(oldest_id)
            
        for rid in expired_ids:
            if rid in self._events:
                del self._events[rid]
            if rid in self._created_at:
                del self._created_at[rid]
            self._completed.discard(rid)
            logging.warning(f"Diagnostic store dropped unconsumed stream: {rid}")
    
    async def stream(self, response_id: str) -> AsyncGenerator[AgentFrameworkEvent, None]:
        """
        Stream events for a specific response_id.
        
        Yields:
            AgentFrameworkEvent objects.
            
        Args:
            response_id: The unique identifier for the response stream to consume.
        """
        if response_id not in self._events:
            # Queue doesn't exist yet — create it and wait.
            # This handles the race where the diagnostic consumer connects
            # before the main stream starts producing events.
            self._cleanup()
            if len(self._events) >= self._max_stream_capacity:
                logging.warning(f"Diagnostic stream capacity reached, rejecting stream for: {response_id}")
                return
            self._events[response_id] = asyncio.Queue()
            self._created_at[response_id] = time.time()

        queue = self._events[response_id]
        try:
            while True:
                event = await queue.get()
                if event is None:
                    break
                yield event
        finally:
            if response_id in self._events:
                del self._events[response_id]
            if response_id in self._created_at:
                del self._created_at[response_id]
            self._completed.discard(response_id)

class DiagnosticsManager:
    """
    Controls whether diagnostic event collection is active and manages patching of Workflow methods.
    
    This manager intercepts Workflow.run(stream=True) calls to capture execution events
    and route them to the DiagnosticStore, allowing parallel streaming of standard responses
    and diagnostic information.
    """
    
    def __init__(self):
        """
        Initialize the manager.
        """
        self.store = DiagnosticStore()
        self._original_run = None
        
        self.apply_patches()
    
    def apply_patches(self):
        """
        Monkey-patch Workflow.run to intercept and capture streaming events.
        
        Non-streaming calls (stream=False) pass through untouched.
        """
        if self._original_run:
            return  # Already patched
            
        self._original_run = Workflow.run

        async def _patched_streaming_run(workflow_self, *args, **kwargs):
            response_id = _current_response_id.get() or self._extract_response_id(args, kwargs)

            async for event in self._original_run(workflow_self, *args, **kwargs):
                if response_id:
                    self._capture_event(response_id, event)
                yield event

            if response_id:
                self.store.complete(response_id)

        def patched_run(workflow_self, *args, **kwargs):
            stream = kwargs.get('stream', False)
            if not stream:
                return self._original_run(workflow_self, *args, **kwargs)
            return _patched_streaming_run(workflow_self, *args, **kwargs)

        Workflow.run = patched_run

    def _extract_response_id(self, args, kwargs) -> Optional[str]:
        """
        Extract response_id from method arguments or metadata.
        
        Args:
            args: Positional arguments passed to the method.
            kwargs: Keyword arguments passed to the method.
            
        Returns:
            The extracted response_id string, or None if not found.
        """
        # Check kwargs for metadata
        if 'metadata' in kwargs and isinstance(kwargs['metadata'], dict):
            return kwargs['metadata'].get('response_id')
        
        if 'run_kwargs' in kwargs and isinstance(kwargs['run_kwargs'], dict):
             if 'metadata' in kwargs['run_kwargs'] and isinstance(kwargs['run_kwargs']['metadata'], dict):
                 return kwargs['run_kwargs']['metadata'].get('response_id')

        # Check kwargs directly
        if 'response_id' in kwargs:
            return kwargs['response_id']
            
        # Check message (first arg or kwargs['message'])
        message = kwargs.get('message')
        if not message and args:
            message = args[0]
            
        if hasattr(message, 'metadata') and isinstance(message.metadata, dict):
            return message.metadata.get('response_id')
        
        # Also check if message is a dict with metadata
        if isinstance(message, dict) and 'metadata' in message and isinstance(message['metadata'], dict):
            return message['metadata'].get('response_id')
            
        return None

    def _capture_event(self, response_id: str, event: Any):
        """
        Capture and store a single event.
        We store the raw event object wrapped in AgentFrameworkEvent to minimize overhead 
        and risk on the main execution thread.
        Serialization happens at consumption time (in server.py).
        """
        try:
            wrapper = AgentFrameworkEvent(
                timestamp=time.time(),
                raw_event=event
            )
            self.store.push(response_id, wrapper)
        except Exception as e:
            # Never let diagnostics crash the main workflow
            logging.error(f"Failed to capture diagnostic event: {e}")


class ResponseIdMiddleware(BaseHTTPMiddleware):
    """
    Extracts X-AgentDev-Response-Id header and sets it in current context

    This ID is used to correlate every added information agentdev added (e.g. diagnostic events).

    Uses a custom header instead of request body to not breaking the standard responses API contract.
    """

    async def dispatch(self, request, call_next):
        token = None
        response_id = request.headers.get("x-agentdev-response-id")
        if response_id:
            token = _current_response_id.set(response_id)
        try:
            return await call_next(request)
        finally:
            if token is not None:
                _current_response_id.reset(token)
